  },
  {
    "fieldLabel": "Domain",
    "fieldName": "domain",
    "fieldType": "text",
    "placeholder": "e.g., medical, legal, IR",
    "requiredField": false
  },
  {
    "fieldLabel": "Note Language",
    "fieldName": "note_language",
    "fieldType": "text",
    "placeholder": "ja, en, ko (defaults to source lang)",
    "requiredField": false
  },
  {
    "fieldLabel": "Custom Instructions",
    "fieldName": "custom_instructions",
    "fieldType": "textarea",
    "placeholder": "Additional refinement instructions",
    "requiredField": false
  },
  {
    "fieldLabel": "Exclude Numeric Segments",
    "fieldName": "exclude_numeric_segments",
    "fieldType": "dropdown",
    "fieldOptions": {
      "values": [{ "option": "false" }, { "option": "true" }]
    },
    "requiredField": false
  },
  {
    "fieldLabel": "Remove Hyphenation",
    "fieldName": "remove_hyphenation",
    "fieldType": "dropdown",
    "fieldOptions": {
      "values": [{ "option": "true" }, { "option": "false" }]
    },
    "requiredField": false
  },
  {
    "fieldLabel": "Output Mode",
    "fieldName": "output_mode",
